#include <bits/stdc++.h>
using namespace std;

void recursiveBubbleSort(vector<long long>& arr, int n) {
    if (n <= 1) return;
    for (int i = 0; i < n-1; i++) {
        if (arr[i] > arr[i+1]) {
            swap(arr[i], arr[i+1]);
        }
    }
    recursiveBubbleSort(arr, n-1);
}

