    int n;
    if (!(cin >> n)) return 0;
    vector<long long> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    recursiveBubbleSort(nums, n);
    for (int i = 0; i < n; i++) {
